            this.loadedAfterClose = loadedAfterClose;
            this.unloadedBeforeClose = unloadedBeforeClose;
            this.unloadedAfterClose = unloadedAfterClose;
        }

        private String toJson() {
            return "{"
                + "\"first\":\"" + first + "\","
                + "\"last\":\"" + last + "\","
                + "\"start\":" + toJsonArray(start) + ","
                + "\"end\":" + toJsonArray(end) + ","
